click.customFunction:
let entityId = widgetContext.stateController.getEntityId('defaultEntity');
widgetContext.http.post('/api/rpc/oneway/' + entityId.id, {
    method: "setConnected",
    params: true,
    timeout: 5000
}).subscribe(
    function() { widgetContext.showSuccessToast('Pripojené!'); },
    function(e) { widgetContext.showErrorToast('Chyba: ' + e.status); }
);

